+/// Zell Utilities
+/// Optimized helpers imported from metal0 for maximum performance
+///
+/// Usage:
+///   const utils = @import("utils.zig");
+///
+///   // Fast string hashmap (40-50% faster than std.StringHashMap)
+///   var map = utils.StringHashMap(i32).init(allocator);
+///
+///   // Fast allocator (2-5x faster in release builds)
+///   const mem = try utils.fast_allocator.alloc(u8, 1024);
+///
+///   // Per-request arena
+///   var arena = utils.createArena();
+///   defer arena.deinit();
+
+pub const wyhash = @import("utils/wyhash.zig");
+pub const hashmap = @import("utils/hashmap.zig");
+pub const allocator = @import("utils/allocator.zig");
+
+// Re-export commonly used types
+pub const StringHashMap = hashmap.StringHashMap;
+pub const StringHashMapUnmanaged = hashmap.StringHashMapUnmanaged;
+pub const WyhashStringContext = hashmap.WyhashStringContext;
+
+pub const fast_allocator = allocator.fast_allocator;
+pub const createArena = allocator.createArena;
+pub const ScratchBuffer = allocator.ScratchBuffer;
+pub const useFastAllocator = allocator.useFastAllocator;
+
+test {
+    _ = wyhash;
+    _ = hashmap;
+    _ = allocator;
+}

