+/// Allocator selection for zell - optimized for inference workloads
+/// Imported from metal0
+///
+/// Strategy:
+/// - Release builds (native): c_allocator - fastest, OS reclaims at exit
+/// - Debug builds: GPA with safety checks for leak detection
+/// - WASM: GPA (c_allocator not available)
+///
+/// Note: c_allocator in release mode means memory is not explicitly freed.
+/// This is intentional for inference servers where model stays loaded and
+/// OS cleanup at exit is acceptable (same pattern as Go, many Rust CLIs).
+///
+/// For long-running servers, use arena allocators for per-request allocations
+/// that get freed together.
+const std = @import("std");
+const builtin = @import("builtin");
+
+/// Fast allocator - drop-in replacement for page_allocator
+/// - Release native: c_allocator (2-5x faster than page_allocator)
+/// - Debug/WASM: page_allocator (for safety/compatibility)
+///
+/// Use this instead of std.heap.page_allocator for hot paths!
+pub const fast_allocator: std.mem.Allocator = blk: {
+    const is_wasm = (builtin.target.cpu.arch == .wasm32 or builtin.target.cpu.arch == .wasm64);
+    const is_debug = (builtin.mode == .Debug);
+    break :blk if (is_wasm or is_debug) std.heap.page_allocator else std.heap.c_allocator;
+};
+
+/// Returns true if we should use c_allocator (fast path, no cleanup needed)
+pub fn useFastAllocator() bool {
+    const is_wasm = comptime (builtin.target.cpu.arch == .wasm32 or builtin.target.cpu.arch == .wasm64);
+    const is_debug = comptime (builtin.mode == .Debug);
+    return comptime (!is_wasm and !is_debug);
+}
+
+/// Get the appropriate allocator for runtime code
+/// - Release native: c_allocator (fast, no GPA needed)
+/// - Debug/WASM: GPA allocator (safe, leak detection)
+pub fn getAllocator(gpa_ptr: anytype) std.mem.Allocator {
+    if (comptime useFastAllocator()) {
+        return std.heap.c_allocator;
+    }
+    return gpa_ptr.allocator();
+}
+
+/// Get allocator type at comptime (for struct fields)
+/// - Native release: void (c_allocator has no state)
+/// - Debug/WASM: GPA type
+pub fn AllocatorType() type {
+    comptime {
+        const is_wasm = builtin.target.cpu.arch == .wasm32 or builtin.target.cpu.arch == .wasm64;
+        const is_debug = builtin.mode == .Debug;
+
+        if (is_wasm or is_debug) {
+            return std.heap.GeneralPurposeAllocator(.{});
+        }
+    }
+
+    // For native release builds, c_allocator has no state
+    return void;
+}
+
+/// Create an arena allocator backed by fast_allocator
+/// Great for per-request allocations that get freed together
+pub fn createArena() std.heap.ArenaAllocator {
+    return std.heap.ArenaAllocator.init(fast_allocator);
+}
+
+/// Thread-local scratch buffer for temporary allocations
+/// Avoids repeated allocations for small temporary data
+pub const ScratchBuffer = struct {
+    const SIZE = 64 * 1024; // 64KB scratch space
+
+    buffer: [SIZE]u8 = undefined,
+    fba: std.heap.FixedBufferAllocator,
+
+    pub fn init() ScratchBuffer {
+        var self = ScratchBuffer{
+            .buffer = undefined,
+            .fba = undefined,
+        };
+        self.fba = std.heap.FixedBufferAllocator.init(&self.buffer);
+        return self;
+    }
+
+    pub fn allocator(self: *ScratchBuffer) std.mem.Allocator {
+        return self.fba.allocator();
+    }
+
+    pub fn reset(self: *ScratchBuffer) void {
+        self.fba.reset();
+    }
+};
+
+test "fast_allocator works" {
+    const mem = try fast_allocator.alloc(u8, 1024);
+    defer fast_allocator.free(mem);
+    try std.testing.expect(mem.len == 1024);
+}
+
+test "arena allocator" {
+    var arena = createArena();
+    defer arena.deinit();
+
+    const alloc = arena.allocator();
+    const mem = try alloc.alloc(u8, 4096);
+    try std.testing.expect(mem.len == 4096);
+    // No need to free - arena.deinit() handles it
+}
+
+test "scratch buffer" {
+    var scratch = ScratchBuffer.init();
+
+    const mem = try scratch.allocator().alloc(u8, 1024);
+    try std.testing.expect(mem.len == 1024);
+
+    scratch.reset();
+
+    // Can allocate again after reset
+    const mem2 = try scratch.allocator().alloc(u8, 2048);
+    try std.testing.expect(mem2.len == 2048);
+}

