+/// Optimized HashMap utilities for zell
+/// Imported from metal0 - use these instead of std.StringHashMap for performance!
+///
+/// Performance gains:
+/// - wyhash: ~40-50% faster than default hash (same as Bun)
+/// - ArrayHashMap: O(n) iteration, better cache locality
+///
+/// Used by: tokenizer vocab lookups, model metadata, server request routing
+const std = @import("std");
+const wyhash = @import("wyhash.zig");
+
+/// Fast string hash context using wyhash (same as Bun)
+/// Returns u32 for ArrayHashMap compatibility
+pub const WyhashStringContext = struct {
+    pub fn hash(_: @This(), key: []const u8) u32 {
+        return @truncate(wyhash.WyhashStateless.hash(0, key));
+    }
+
+    pub fn eql(_: @This(), a: []const u8, b: []const u8, b_index: usize) bool {
+        _ = b_index;
+        return std.mem.eql(u8, a, b);
+    }
+};
+
+/// Fast string-keyed ArrayHashMap with wyhash
+/// Use this instead of std.StringHashMap!
+///
+/// API changes from HashMap:
+/// - .keyIterator() -> .keys() (returns slice)
+/// - .valueIterator() -> .values() (returns slice)
+/// - .iterator() -> iterate over .keys() and .values() together
+///
+/// Example:
+///   var map = hashmap.StringHashMap(ValueType).init(allocator);
+///   for (map.keys()) |key| { ... }
+pub fn StringHashMap(comptime V: type) type {
+    return std.ArrayHashMap([]const u8, V, WyhashStringContext, true);
+}
+
+/// Unmanaged version (no allocator stored, caller manages memory)
+pub fn StringHashMapUnmanaged(comptime V: type) type {
+    return std.ArrayHashMapUnmanaged([]const u8, V, WyhashStringContext, true);
+}
+
+/// AutoHashMap with wyhash for non-string keys
+/// For integer keys, this uses the standard AutoContext
+pub fn AutoHashMap(comptime K: type, comptime V: type) type {
+    return std.AutoArrayHashMap(K, V);
+}
+
+/// Helper to create a pre-sized StringHashMap
+pub fn initStringHashMapCapacity(comptime V: type, allocator: std.mem.Allocator, capacity: u32) !StringHashMap(V) {
+    var map = StringHashMap(V).init(allocator);
+    try map.ensureTotalCapacity(capacity);
+    return map;
+}
+
+test "StringHashMap basic operations" {
+    const allocator = std.testing.allocator;
+    var map = StringHashMap(i32).init(allocator);
+    defer map.deinit();
+
+    try map.put("hello", 1);
+    try map.put("world", 2);
+
+    try std.testing.expectEqual(@as(i32, 1), map.get("hello").?);
+    try std.testing.expectEqual(@as(i32, 2), map.get("world").?);
+    try std.testing.expectEqual(@as(?i32, null), map.get("foo"));
+}
+
+test "StringHashMap iteration" {
+    const allocator = std.testing.allocator;
+    var map = StringHashMap(i32).init(allocator);
+    defer map.deinit();
+
+    try map.put("a", 1);
+    try map.put("b", 2);
+    try map.put("c", 3);
+
+    var sum: i32 = 0;
+    for (map.values()) |v| {
+        sum += v;
+    }
+    try std.testing.expectEqual(@as(i32, 6), sum);
+}

